    AND order_id = #{orderId}
    AND status = #{status}
    AND LOWER(invoice_number) LIKE LOWER(CONCAT('%', #{invoiceNumber}, '%'))
    AND customer_id = #{customerId}
    AND (
        LOWER(invoice_number) LIKE LOWER(CONCAT('%', #{q}, '%'))
        OR order_id LIKE CONCAT('%', #{q}, '%')
        OR customer_name LIKE CONCAT('%', #{q}, '%')
        OR order_number LIKE CONCAT('%', #{q}, '%')
    )

